const styles = {
  container: { padding: 32, maxWidth: 900, margin: '0 auto' },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', margin: 0 },
  subtitle: { color: '#64748b', marginTop: 8, marginBottom: 28, fontSize: 15 },
  card: {
    background: '#fff', borderRadius: 20, padding: 32,
    boxShadow: '0 4px 24px rgba(0,0,0,0.07)', marginBottom: 24,
    border: '1px solid #f1f5f9',
  },
  row: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 },
  formGroup: { marginBottom: 20 },
  label: { display: 'block', fontWeight: 600, color: '#374151', marginBottom: 6, fontSize: 14 },
  input: {
    width: '100%', padding: '12px 16px', borderRadius: 10,
    border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none',
    transition: 'border-color 0.2s', boxSizing: 'border-box', color: '#1e293b',
  },
  select: {
    width: '100%', padding: '12px 16px', borderRadius: 10,
    border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none',
    color: '#1e293b', background: '#fff',
  },
  textarea: {
    width: '100%', padding: '12px 16px', borderRadius: 10,
    border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none',
    resize: 'vertical', fontFamily: 'inherit', boxSizing: 'border-box', color: '#1e293b',
  },
  previewBtn: {
    background: 'linear-gradient(135deg, #667eea, #764ba2)', color: '#fff',
    border: 'none', padding: '12px 28px', borderRadius: 12,
    cursor: 'pointer', fontSize: 15, fontWeight: 600,
  },
  previewSection: { marginTop: 8 },
  previewTitle: { fontSize: 20, fontWeight: 700, color: '#1e293b', marginBottom: 16 },
  noClasses: { background: '#f0fdf4', color: '#166534', padding: 20, borderRadius: 12, fontSize: 15 },
  slotGrid: { display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 16, marginBottom: 20 },
  slotCard: {
    background: '#fff', borderRadius: 16, padding: 20,
    boxShadow: '0 2px 16px rgba(0,0,0,0.06)', border: '1px solid #e2e8f0',
  },
  slotHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 },
  slotDay: { fontWeight: 700, color: '#1e293b', fontSize: 14 },
  slotPeriod: {
    background: '#dbeafe', color: '#1d4ed8', borderRadius: 20,
    padding: '3px 12px', fontSize: 12, fontWeight: 600,
  },
  slotDetails: { display: 'flex', gap: 16, color: '#64748b', fontSize: 13, marginBottom: 12 },
  subsSection: {},
  subsLabel: { fontWeight: 600, color: '#374151', fontSize: 13, marginBottom: 8 },
  noSub: { background: '#fef2f2', color: '#dc2626', borderRadius: 8, padding: '8px 12px', fontSize: 13 },
  subsList: { display: 'flex', flexWrap: 'wrap', gap: 6 },
  subChip: {
    background: '#f0fdf4', color: '#166534', borderRadius: 20,
    padding: '4px 10px', fontSize: 12, fontWeight: 500,
  },
  moreChip: {
    background: '#f1f5f9', color: '#64748b', borderRadius: 20,
    padding: '4px 10px', fontSize: 12,
  },
  autoNote: {
    display: 'flex', gap: 10, alignItems: 'flex-start',
    background: '#eff6ff', color: '#1e40af', borderRadius: 12,
    padding: '12px 16px', fontSize: 13, marginBottom: 20,
  },
  submitBtn: {
    background: 'linear-gradient(135deg, #10b981, #059669)', color: '#fff',
    border: 'none', padding: '14px 36px', borderRadius: 12,
    cursor: 'pointer', fontSize: 16, fontWeight: 700, width: '100%',
  },
  successBox: {
    background: '#fff', borderRadius: 24, padding: 60, textAlign: 'center',
    boxShadow: '0 8px 40px rgba(0,0,0,0.08)', maxWidth: 500, margin: '80px auto',
  },
  successIcon: { fontSize: 64, marginBottom: 16 },
  successTitle: { fontSize: 24, fontWeight: 800, color: '#1e293b', marginBottom: 12 },
  successMsg: { color: '#64748b', fontSize: 15, lineHeight: 1.6 },
};
